VALUES
  ('social-worker-moex-06770', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '兒童的家外安置被視為是兒童福利服務的最後一道防線，其最主要的原因為何？', '["家外安置的服務提供者不易培養，供給有限", "家外安置的服務成本太高，排擠其他兒童福利資源", "研究顯示，長期接受寄養或機構服務的兒童，在不同照顧系統間流轉，其心理創傷及行為問題的改變 成效一直備受質疑", "家外安置服務的專業系統太為複雜，對兒童會有適應上的困難"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "9d32e5b6c8d6", "answer_pdf_sha1": "6bba627e5ea0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06771', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '根據世界衛生組織發展的ICF（International Classification of Functioning, Disability and Health）「國際健康 功能與身心障礙分類系統」，一個人整體身心健康狀態的評估應包括「功能運作與障礙」及「情境脈絡 因素」兩部分。其在「功能運作與障礙」面向，主要評估的重點包括：', '["身體功能與身體結構", "身心功能及社會參與", "身體功能與身體結構、活動能力、社會參與情形", "身心功能及社會障礙因素"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "9d32e5b6c8d6", "answer_pdf_sha1": "6bba627e5ea0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06772', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '近年來國內身心障礙團體積極推動的自立生活（independent living），其所依據的理念與實際運作，與下 列何者較無相關？', '["自立生活強調應致力於增進障礙者全面自理生活能力及正面的社會角色形象", "自立生活主張障礙者有權得到支持，協助其在社區中生活，外在環境需要調整改善", "社會模式觀點是自立生活推動的重要理論基礎", "個人助理制度是障礙者自立生活的重要服務項目之一"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "9d32e5b6c8d6", "answer_pdf_sha1": "6bba627e5ea0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06773', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在女性主義的流派中，那一個流派有下列的主張：男性透過對女性施展暴力並控制女性，造成家庭內壓 迫女性的不平等關係？', '["自由主義女性主義", "馬克思主義女性主義", "基變女性主義", "社會主義女性主義"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "9d32e5b6c8d6", "answer_pdf_sha1": "6bba627e5ea0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06774', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '面對不斷發生之天然災害，社會工作人員在災難管理中占有不可或缺的角色。若將災難管理依其階段性 之工作分類，有關社工人員針對災民的緊急救援，提供災民及救災人員悲傷輔導、壓力管理等服務，通 常是屬於那一個階段的重要任務？', '["災難應變期", "災難整備期", "災難預防期", "災難復原期"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "9d32e5b6c8d6", "answer_pdf_sha1": "6bba627e5ea0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06775', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '根據2012年美國社會工作人員協會（National Association of Social Workers, NASW）所制定的學校社會工 作人員服務標準，下列那一項並非學校社會工作人員的主要職責？', '["為社會及經濟弱勢學生倡導權益", "確保身心障礙學生獲得公平教育機會", "促成學校、家庭及社區的合作，改善學生的學習、情緒與行為問題", "參與學生學業成就評量，與教師一起擬訂改善學業策略"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "9d32e5b6c8d6", "answer_pdf_sha1": "6bba627e5ea0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06776', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '對於貧窮的原因，「貧窮文化」是一個存在已久的解釋觀點。下列那一個選項與這個論點無關或者相悖？', '["「貧窮文化」的主要提倡者是Oscar Lewis", "貧窮文化的論點是指兒童在貧窮環境成長時，會學習貧窮的生活習性，並對未來生活造成影響", "貧窮文化指貧窮的產生導因於結構性的文化因素與制度", "貧窮文化指的是窮人的信念、價值與目標，很明顯的與其他社會階層不同"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "9d32e5b6c8d6", "answer_pdf_sha1": "6bba627e5ea0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06777', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在社會工作專業倫理中，文獻常引用美國學者Beauchamp 及Childress提出的生物醫學倫理（biomedical ethics）四項原則，下列何者是正確的？', '["自主原則、責任原則、善待原則、正義原則", "自主原則、不傷害原則、善待原則、正義原則", "自主原則、不傷害原則、包容原則、合作原則", "包容原則、合作原則、善待原則、責任原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "9d32e5b6c8d6", "answer_pdf_sha1": "6bba627e5ea0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06778', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '依民國98年修正公布的「社會工作師法」第23條規定：「社會工作師證照不得出租或出借給他人使用」。 對於租借證照使用者，該法的罰則如何規定？', '["立即停止營業，並禁止租借證照者參與社會工作師考試", "處新臺幣三十萬元以上五十萬元以下罰鍰", "處新臺幣十五萬元以上三十萬元以下罰鍰", "處新臺幣二萬元以上十萬元以下罰鍰"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "9d32e5b6c8d6", "answer_pdf_sha1": "6bba627e5ea0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06779', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列有關「職業福利」（occupational welfare）的敘述，何者是不正確的？', '["職業福利是社會福利民營化中的一項重要體現", "職業福利是由雇主個人對受僱者的施惠行為，與政府無關", "職業福利是依職業身分、工作成就等，由雇主提供受僱者的現金或實物給付", "職業福利是必須進入就業市場者才能取得"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "9d32e5b6c8d6", "answer_pdf_sha1": "6bba627e5ea0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
